command:
tmpfile="$(mktemp)"; metrics="$(curl -L --output "$tmpfile" --silent --show-error --write-out 'DL_BYTES=%{size_download}
DL_SECONDS=%{time_total}
DL_MPS=%{speed_download}
' https://speed.hetzner.de/10MB.bin)"; rc=$?; rm -f "$tmpfile"; printf 'BACKEND=curl
%s' "$metrics"; python3 -c 'import re,sys; text=sys.stdin.read(); m=re.search(r"DL_MPS=([0-9.]+)", text); print("DOWNLOAD_MBPS=" + (f"{float(m.group(1))*8/1000000:.2f}" if m else "unknown"))' <<'EOF'
$metrics
EOF
